import { writeFileSync } from 'node:fs'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

import { light, dark } from '../tailwind/theme-tokens.mjs'

const projectRoot = resolve(dirname(fileURLToPath(import.meta.url)), '..')

const header =
  '// AUTO-GENERATED from tailwind/theme-tokens.mjs — run `npm run build:tokens` to update.\n// Do not edit this file by hand.\n\n'

const renderScss = (prefix, tokens) =>
  header +
  Object.entries(tokens)
    .map(([name, value]) => `$color-${prefix}-${name}: ${value};`)
    .join('\n') +
  '\n'

const targets = [
  ['src/globals/theme/theme-light.scss', renderScss('light', light)],
  ['src/globals/theme/theme-dark.scss', renderScss('dark', dark)],
]

for (const [relativePath, contents] of targets) {
  const absolutePath = resolve(projectRoot, relativePath)
  writeFileSync(absolutePath, contents)
  console.log(`wrote ${relativePath}`)
}
